patterns.how_to:
# CLI
devforge snapshot my.snapshot.json --project-config my.project_config.json

# project_config.json structure:
{
  "projects": {
    "my-project-id": {
      "llm_preferences": {
        "provider": "openrouter",
        "planning_model": "openai/gpt-5.4-mini",
        "retry_model": "google/gemini-2.5-flash"
      },
      "knowledge_preferences": {
        "preferred_ids": ["phase.testing"],
        "excluded_ids": ["phase.analysis_design"]
      },
      "pull_policy_overrides": [
        {"executor": "codex", "mode": "structured", "budget": 8000}
      ]
    }
  }
}

from devforge.executors.adapters import BaseExecutorAdapter
from devforge.executors import register_executor_adapter
from devforge.state import ExecutorResult

class AiderAdapter(BaseExecutorAdapter):
    def __init__(self):
        super().__init__(
            name='aider',
            supported_phases=('implementation', 'testing'),
            supported_roles=('software_engineer', 'qa_engineer')
        )

    def normalize_result(self, raw_result):
        return ExecutorResult(
            work_package_id=raw_result.get('work_package_id', ''),
            status='completed' if raw_result.get('exit_code') == 0 else 'failed',
            summary=raw_result.get('output', ''),
            findings=[],
            artifacts_created=[],
            handoff_notes=[]
        )

register_executor_adapter(AiderAdapter())

from devforge.knowledge import KNOWLEDGE_REGISTRY, KnowledgeDocument

custom_doc = KnowledgeDocument(
    doc_id='domain.fintech',
    title='Fintech Domain Knowledge',
    content='## Compliance\n- PCI-DSS requirements...\n',
    tags=['fintech', 'compliance', 'security'],
    applicable_phases=['analysis_design', 'implementation'],
    applicable_archetypes=['fintech', 'banking']
)
KNOWLEDGE_REGISTRY['domain.fintech'] = custom_doc

# In project_config.json:
{
  "projects": {
    "my-project": {
      "knowledge_preferences": {
        "preferred_ids": ["domain.fintech"]
      }
    }
  }
}
